using System;
class Pipeline {
    private List<Func<string, string>> _middleware = new();
    public void Use(Func<string, string> mw) => _middleware.Add(mw);
    public string Execute(string input) {
        string result = input;
        foreach (var mw in _middleware)
            result = mw(result);
        return result;
    }
}
class Program {
    static void Main() {
        var p = new Pipeline();
        p.Use(s => s.ToUpper());
        p.Use(s => s.Trim());
        Console.WriteLine(p.Execute("  hello  "));
    }
}

