using System;
abstract record Result<T> {
    public record Ok(T Value) : Result<T>;
    public record Error(string Message) : Result<T>;
}
class Program {
    static Result<int> Divide(int a, int b) =>
        b == 0 ? new Result<int>.Error("Division by zero") : new Result<int>.Ok(a / b);
    static void Main() {
        var r = Divide(10, 3);
        string msg = r switch {
            Result<int>.Ok(var v) => $"Result: {v}",
            Result<int>.Error(var e) => $"Error: {e}",
            _ => "Unknown"
        };
        Console.WriteLine(msg);
    }
}
